      },
      {
        name: 'Ice Cream Sundae',
        price: 'KSh 690',
        image: 'https://images.unsplash.com/photo-1563805042-7684c019e1cb?auto=format&fit=crop&w=900&q=80',
      },
      {
        name: 'Fresh Strawberry Mocktail',
        price: 'KSh 560',
